function run_delta_policy_dual_onesample_ttest(varargin)
% =========================================================================
% SPM12 second-level one-sample t-test for delta_policy_dual slope maps
%
% This script performs a group-level one-sample t-test on participant-level
% voxel-wise slope maps generated by the model:
%
%   delta_policy_dual
%       = intercept + beta * pattern_change
%
% Two directional contrasts are created:
%
%   1. Mean slope > 0
%   2. Mean slope < 0
%
% -------------------------------------------------------------------------
% Expected input structure
% -------------------------------------------------------------------------
%
% <first_level_dir>/
% ├── Sub02_regression_patternchange2delta_policy_dual.nii
% ├── Sub03_regression_patternchange2delta_policy_dual.nii
% └── ...
%
% Both .nii and .nii.gz input files are supported.
%
% -------------------------------------------------------------------------
% Default output structure
% -------------------------------------------------------------------------
%
% outputs/
% └── patternchange_to_delta_policy_dual_second_level/
%     ├── SPM.mat
%     ├── beta_0001.nii
%     ├── ResMS.nii
%     ├── con_0001.nii
%     ├── con_0002.nii
%     ├── spmT_0001.nii
%     ├── spmT_0002.nii
%     ├── included_subjects.txt
%     └── batch_one_sample_t.mat
%
% -------------------------------------------------------------------------
% Example
% -------------------------------------------------------------------------
%
% run_delta_policy_dual_onesample_ttest( ...
%     'first_level_dir', '/path/to/first_level_maps', ...
%     'second_level_dir', '/path/to/group_results');
%
% With an explicit mask:
%
% run_delta_policy_dual_onesample_ttest( ...
%     'explicit_mask', '/path/to/group_mask.nii');
%
% Prevent replacement of an existing model:
%
% run_delta_policy_dual_onesample_ttest( ...
%     'overwrite_existing', false);
%
% Dependency
% ----------
% SPM12
% =========================================================================

clc;

%% ========================================================================
% 0. Parse settings
% ========================================================================

script_path = mfilename('fullpath');
script_dir = fileparts(script_path);

default_first_level_dir = fullfile( ...
    script_dir, ...
    'outputs', ...
    'patternchange_to_delta_policy_dual' ...
);

default_second_level_dir = fullfile( ...
    script_dir, ...
    'outputs', ...
    'patternchange_to_delta_policy_dual_second_level' ...
);

parser = inputParser;

addParameter( ...
    parser, ...
    'first_level_dir', ...
    default_first_level_dir, ...
    @(x) ischar(x) || isstring(x) ...
);

addParameter( ...
    parser, ...
    'second_level_dir', ...
    default_second_level_dir, ...
    @(x) ischar(x) || isstring(x) ...
);

addParameter( ...
    parser, ...
    'explicit_mask', ...
    '', ...
    @(x) ischar(x) || isstring(x) ...
);

addParameter( ...
    parser, ...
    'minimum_subjects', ...
    3, ...
    @(x) isnumeric(x) && isscalar(x) && x >= 2 ...
);

addParameter( ...
    parser, ...
    'overwrite_existing', ...
    true, ...
    @(x) islogical(x) && isscalar(x) ...
);

addParameter( ...
    parser, ...
    'affine_tolerance', ...
    1e-4, ...
    @(x) isnumeric(x) && isscalar(x) && x >= 0 ...
);

parse(parser, varargin{:});

first_level_dir = char( ...
    parser.Results.first_level_dir ...
);

second_level_dir = char( ...
    parser.Results.second_level_dir ...
);

explicit_mask = char( ...
    parser.Results.explicit_mask ...
);

minimum_subjects = ...
    parser.Results.minimum_subjects;

overwrite_existing = ...
    parser.Results.overwrite_existing;

affine_tolerance = ...
    parser.Results.affine_tolerance;

%% ========================================================================
% 1. Validate SPM and paths
% ========================================================================

if exist('spm', 'file') ~= 2
    error( ...
        ['SPM12 was not found on the MATLAB path. ', ...
         'Install SPM12 and add it to the MATLAB path.'] ...
    );
end

if exist(first_level_dir, 'dir') ~= 7
    error( ...
        'First-level directory does not exist:\n%s', ...
        first_level_dir ...
    );
end

if ...
        ~isempty(explicit_mask) ...
        && exist(explicit_mask, 'file') ~= 2

    error( ...
        'Explicit mask does not exist:\n%s', ...
        explicit_mask ...
    );
end

if exist(second_level_dir, 'dir') ~= 7
    mkdir(second_level_dir);
end

input_cache_dir = fullfile( ...
    second_level_dir, ...
    '_spm_input_cache' ...
);

if exist(input_cache_dir, 'dir') ~= 7
    mkdir(input_cache_dir);
end

%% ========================================================================
% 2. Initialize SPM
% ========================================================================

spm('Defaults', 'fMRI');
spm_jobman('initcfg');

%% ========================================================================
% 3. Prepare optional explicit mask
% ========================================================================

if isempty(explicit_mask)

    prepared_explicit_mask = '';

else
    mask_cache_dir = fullfile( ...
        input_cache_dir, ...
        'explicit_mask' ...
    );

    prepared_mask_path = prepare_spm_nifti( ...
        explicit_mask, ...
        mask_cache_dir ...
    );

    prepared_explicit_mask = add_volume_index( ...
        prepared_mask_path ...
    );
end

%% ========================================================================
% 4. Collect participant-level slope maps
% ========================================================================

subject_maps = find_subject_maps( ...
    first_level_dir ...
);

if isempty(subject_maps)
    error( ...
        ['No participant-level maps matching the expected filename ', ...
         'were found in:\n%s'], ...
        first_level_dir ...
    );
end

scans = {};
included_subjects = {};
source_files = {};

for map_index = 1:numel(subject_maps)

    source_path = fullfile( ...
        subject_maps(map_index).folder, ...
        subject_maps(map_index).name ...
    );

    subject_name = extract_subject_name( ...
        subject_maps(map_index).name ...
    );

    subject_cache_dir = fullfile( ...
        input_cache_dir, ...
        subject_name ...
    );

    try
        prepared_path = prepare_spm_nifti( ...
            source_path, ...
            subject_cache_dir ...
        );

    catch preparation_error

        fprintf( ...
            '[Skipped] %s: %s\n', ...
            subject_maps(map_index).name, ...
            preparation_error.message ...
        );

        continue;
    end

    scans{end + 1, 1} = ...
        add_volume_index(prepared_path); %#ok<AGROW>

    included_subjects{end + 1, 1} = ...
        subject_name; %#ok<AGROW>

    source_files{end + 1, 1} = ...
        source_path; %#ok<AGROW>
end

number_of_subjects = numel(scans);

fprintf('\n============================================================\n');
fprintf('delta_policy_dual second-level one-sample t-test\n');
fprintf('============================================================\n');

fprintf( ...
    'First-level directory:  %s\n', ...
    first_level_dir ...
);

fprintf( ...
    'Second-level directory: %s\n', ...
    second_level_dir ...
);

fprintf( ...
    'Participant maps:       %d\n', ...
    number_of_subjects ...
);

fprintf( ...
    'Minimum subjects:       %d\n', ...
    minimum_subjects ...
);

fprintf( ...
    'Overwrite existing:     %d\n', ...
    overwrite_existing ...
);

if isempty(explicit_mask)
    fprintf('Explicit mask:          none\n');
else
    fprintf( ...
        'Explicit mask:          %s\n', ...
        explicit_mask ...
    );
end

fprintf('============================================================\n');

if number_of_subjects < minimum_subjects
    error( ...
        ['Too few participant maps for the one-sample t-test: ', ...
         '%d < %d'], ...
        number_of_subjects, ...
        minimum_subjects ...
    );
end

%% ========================================================================
% 5. Validate image dimensions and affine matrices
% ========================================================================

validate_scan_grids( ...
    scans, ...
    prepared_explicit_mask, ...
    affine_tolerance ...
);

%% ========================================================================
% 6. Prepare the output directory
% ========================================================================

prepare_output_directory( ...
    second_level_dir, ...
    overwrite_existing ...
);

%% ========================================================================
% 7. Specify the one-sample t-test
% ========================================================================

matlabbatch = {};

% -------------------------------------------------------------------------
% Factorial design specification
% -------------------------------------------------------------------------

matlabbatch{1}.spm.stats.factorial_design.dir = {
    second_level_dir
};

matlabbatch{1}.spm.stats.factorial_design ...
    .des.t1.scans = scans;

% No covariates.
matlabbatch{1}.spm.stats.factorial_design.cov = ...
    struct( ...
        'c', {}, ...
        'cname', {}, ...
        'iCFI', {}, ...
        'iCC', {} ...
    );

matlabbatch{1}.spm.stats.factorial_design.multi_cov = ...
    struct( ...
        'files', {}, ...
        'iCFI', {}, ...
        'iCC', {} ...
    );

% Disable threshold masking.
matlabbatch{1}.spm.stats.factorial_design ...
    .masking.tm.tm_none = 1;

% Enable implicit masking.
matlabbatch{1}.spm.stats.factorial_design ...
    .masking.im = 1;

if isempty(prepared_explicit_mask)

    matlabbatch{1}.spm.stats.factorial_design ...
        .masking.em = {''};

else
    matlabbatch{1}.spm.stats.factorial_design ...
        .masking.em = {
            prepared_explicit_mask
        };
end

% Disable global calculation and scaling.
matlabbatch{1}.spm.stats.factorial_design ...
    .globalc.g_omit = 1;

matlabbatch{1}.spm.stats.factorial_design ...
    .globalm.gmsca.gmsca_no = 1;

matlabbatch{1}.spm.stats.factorial_design ...
    .globalm.glonorm = 1;

%% ========================================================================
% 8. Estimate the second-level model
% ========================================================================

spm_mat_path = fullfile( ...
    second_level_dir, ...
    'SPM.mat' ...
);

matlabbatch{2}.spm.stats.fmri_est.spmmat = {
    spm_mat_path
};

matlabbatch{2}.spm.stats.fmri_est ...
    .write_residuals = 0;

matlabbatch{2}.spm.stats.fmri_est ...
    .method.Classical = 1;

%% ========================================================================
% 9. Define positive and negative contrasts
% ========================================================================

matlabbatch{3}.spm.stats.con.spmmat = {
    spm_mat_path
};

% Delete existing contrasts before creating the requested contrasts.
matlabbatch{3}.spm.stats.con.delete = 1;

% Positive group mean.
matlabbatch{3}.spm.stats.con.consess{1} ...
    .tcon.name = 'Mean slope > 0';

matlabbatch{3}.spm.stats.con.consess{1} ...
    .tcon.weights = 1;

matlabbatch{3}.spm.stats.con.consess{1} ...
    .tcon.sessrep = 'none';

% Negative group mean.
matlabbatch{3}.spm.stats.con.consess{2} ...
    .tcon.name = 'Mean slope < 0';

matlabbatch{3}.spm.stats.con.consess{2} ...
    .tcon.weights = -1;

matlabbatch{3}.spm.stats.con.consess{2} ...
    .tcon.sessrep = 'none';

%% ========================================================================
% 10. Save and run the SPM batch
% ========================================================================

batch_path = fullfile( ...
    second_level_dir, ...
    'batch_one_sample_t.mat' ...
);

save( ...
    batch_path, ...
    'matlabbatch' ...
);

spm_jobman( ...
    'run', ...
    matlabbatch ...
);

write_subject_manifest( ...
    second_level_dir, ...
    included_subjects ...
);

write_input_manifest( ...
    second_level_dir, ...
    included_subjects, ...
    source_files ...
);

fprintf('\n============================================================\n');
fprintf('Group one-sample t-test completed\n');
fprintf('============================================================\n');

fprintf( ...
    'Participants:           %d\n', ...
    number_of_subjects ...
);

fprintf( ...
    'Positive contrast:      Mean slope > 0\n' ...
);

fprintf( ...
    'Negative contrast:      Mean slope < 0\n' ...
);

fprintf( ...
    'Output directory:       %s\n', ...
    second_level_dir ...
);

fprintf('============================================================\n');

end


%% ========================================================================
% Local helper functions
% ========================================================================

function subject_maps = find_subject_maps(first_level_dir)
% Find participant slope maps in .nii or .nii.gz format.

patterns = {
    'Sub*_regression_patternchange2delta_policy_dual.nii', ...
    'Sub*_regression_patternchange2delta_policy_dual.nii.gz' ...
};

subject_maps = [];

for pattern_index = 1:numel(patterns)

    matching_files = dir( ...
        fullfile( ...
            first_level_dir, ...
            patterns{pattern_index} ...
        ) ...
    );

    for file_index = 1:numel(matching_files)

        filename = matching_files(file_index).name;

        is_valid_name = ~isempty( ...
            regexp( ...
                filename, ...
                ['^Sub\d+_regression_', ...
                 'patternchange2delta_policy_dual\.nii(\.gz)?$'], ...
                'once' ...
            ) ...
        );

        if is_valid_name
            subject_maps = [
                subject_maps
                matching_files(file_index)
            ]; %#ok<AGROW>
        end
    end
end

if isempty(subject_maps)
    return;
end

% Remove duplicate .nii/.nii.gz representations of the same participant.
subject_names = cell( ...
    numel(subject_maps), ...
    1 ...
);

for index = 1:numel(subject_maps)

    subject_names{index} = extract_subject_name( ...
        subject_maps(index).name ...
    );
end

subject_numbers = zeros( ...
    numel(subject_names), ...
    1 ...
);

for index = 1:numel(subject_names)

    numeric_token = regexp( ...
        subject_names{index}, ...
        '\d+', ...
        'match', ...
        'once' ...
    );

    subject_numbers(index) = str2double( ...
        numeric_token ...
    );
end

[~, sorting_order] = sort( ...
    subject_numbers ...
);

subject_maps = subject_maps( ...
    sorting_order ...
);

subject_names = subject_names( ...
    sorting_order ...
);

keep = true( ...
    numel(subject_maps), ...
    1 ...
);

for index = 2:numel(subject_maps)

    if strcmpi( ...
            subject_names{index}, ...
            subject_names{index - 1} ...
        )

        previous_is_nii = endsWith( ...
            lower(subject_maps(index - 1).name), ...
            '.nii' ...
        );

        current_is_nii = endsWith( ...
            lower(subject_maps(index).name), ...
            '.nii' ...
        );

        if previous_is_nii
            keep(index) = false;

        elseif current_is_nii
            keep(index - 1) = false;

        else
            keep(index) = false;
        end
    end
end

subject_maps = subject_maps(keep);

end


function subject_name = extract_subject_name(filename)
% Extract a participant identifier such as Sub02 from a filename.

token = regexp( ...
    filename, ...
    '^(Sub\d+)_', ...
    'tokens', ...
    'once' ...
);

if isempty(token)
    error( ...
        'Could not extract participant ID from filename: %s', ...
        filename ...
    );
end

subject_name = token{1};

end


function prepared_path = prepare_spm_nifti( ...
    input_path, ...
    cache_directory ...
)
% Return an uncompressed NIfTI path suitable for SPM.
%
% Uncompressed .nii files are used directly. Compressed .nii.gz files are
% decompressed into the specified cache directory.

input_path = char(input_path);

if exist(input_path, 'file') ~= 2
    error( ...
        'Input image does not exist: %s', ...
        input_path ...
    );
end

if endsWith( ...
        lower(input_path), ...
        '.nii' ...
    )

    prepared_path = input_path;
    return;
end

if ~endsWith( ...
        lower(input_path), ...
        '.nii.gz' ...
    )

    error( ...
        'Unsupported image extension: %s', ...
        input_path ...
    );
end

if exist(cache_directory, 'dir') ~= 7
    mkdir(cache_directory);
end

output_filename = [
    strip_nifti_suffix(input_path), ...
    '.nii' ...
];

prepared_path = fullfile( ...
    cache_directory, ...
    output_filename ...
);

source_information = dir( ...
    input_path ...
);

target_information = dir( ...
    prepared_path ...
);

needs_extraction = ...
    isempty(target_information) ...
    || target_information.datenum < source_information.datenum;

if needs_extraction

    if exist(prepared_path, 'file') == 2
        delete(prepared_path);
    end

    extracted_files = gunzip( ...
        input_path, ...
        cache_directory ...
    );

    if isempty(extracted_files)
        error( ...
            'Failed to decompress NIfTI file: %s', ...
            input_path ...
        );
    end
end

if exist(prepared_path, 'file') ~= 2
    error( ...
        'Decompressed image was not created: %s', ...
        prepared_path ...
    );
end

end


function indexed_path = add_volume_index(file_path)
% Add the SPM volume suffix ",1" when it is absent.

file_path = char(file_path);

if isempty( ...
        regexp( ...
            file_path, ...
            ',\d+$', ...
            'once' ...
        ) ...
    )

    indexed_path = [
        file_path, ...
        ',1' ...
    ];

else
    indexed_path = file_path;
end

end


function clean_path = remove_volume_index(indexed_path)
% Remove a trailing SPM volume suffix such as ",1".

clean_path = regexprep( ...
    char(indexed_path), ...
    ',\d+$', ...
    '' ...
);

end


function validate_scan_grids( ...
    scans, ...
    explicit_mask, ...
    affine_tolerance ...
)
% Verify that all participant maps share dimensions and affine matrices.

reference_path = remove_volume_index( ...
    scans{1} ...
);

reference_volume = spm_vol( ...
    reference_path ...
);

reference_dimensions = ...
    reference_volume(1).dim;

reference_affine = ...
    reference_volume(1).mat;

for scan_index = 1:numel(scans)

    current_path = remove_volume_index( ...
        scans{scan_index} ...
    );

    current_volume = spm_vol( ...
        current_path ...
    );

    if ~isequal( ...
            current_volume(1).dim, ...
            reference_dimensions ...
        )

        error( ...
            ['Image dimensions do not match.\n', ...
             'Reference: %s\nCurrent: %s'], ...
            reference_path, ...
            current_path ...
        );
    end

    maximum_affine_difference = max( ...
        abs( ...
            current_volume(1).mat(:) ...
            - reference_affine(:) ...
        ) ...
    );

    if maximum_affine_difference > affine_tolerance

        error( ...
            ['Image affine does not match.\n', ...
             'Reference: %s\nCurrent: %s\n', ...
             'Maximum difference: %.8g'], ...
            reference_path, ...
            current_path, ...
            maximum_affine_difference ...
        );
    end
end

if ~isempty(explicit_mask)

    mask_path = remove_volume_index( ...
        explicit_mask ...
    );

    mask_volume = spm_vol( ...
        mask_path ...
    );

    if ~isequal( ...
            mask_volume(1).dim, ...
            reference_dimensions ...
        )

        error( ...
            ['Explicit-mask dimensions do not match the input maps.\n', ...
             'Mask: %s\nReference: %s'], ...
            mask_path, ...
            reference_path ...
        );
    end

    maximum_mask_affine_difference = max( ...
        abs( ...
            mask_volume(1).mat(:) ...
            - reference_affine(:) ...
        ) ...
    );

    if maximum_mask_affine_difference > affine_tolerance

        error( ...
            ['Explicit-mask affine does not match the input maps.\n', ...
             'Mask: %s\nReference: %s\n', ...
             'Maximum difference: %.8g'], ...
            mask_path, ...
            reference_path, ...
            maximum_mask_affine_difference ...
        );
    end
end

end


function prepare_output_directory( ...
    output_directory, ...
    overwrite_existing ...
)
% Create the output directory and selectively remove an existing SPM model.

if exist(output_directory, 'dir') ~= 7

    mkdir(output_directory);
    return;
end

existing_spm = fullfile( ...
    output_directory, ...
    'SPM.mat' ...
);

if exist(existing_spm, 'file') ~= 2
    return;
end

if ~overwrite_existing

    error( ...
        ['An existing SPM model was found in:\n%s\n', ...
         'Set overwrite_existing=true to replace it.'], ...
        output_directory ...
    );
end

patterns_to_remove = {
    'SPM.mat', ...
    'mask.nii', ...
    'mask.nii.gz', ...
    'ResMS.nii', ...
    'ResMS.nii.gz', ...
    'RPV.nii', ...
    'RPV.nii.gz', ...
    'beta_*.nii', ...
    'beta_*.nii.gz', ...
    'con_*.nii', ...
    'con_*.nii.gz', ...
    'spmT_*.nii', ...
    'spmT_*.nii.gz', ...
    'spmF_*.nii', ...
    'spmF_*.nii.gz', ...
    'ess_*.nii', ...
    'ess_*.nii.gz', ...
    'ResI_*.nii', ...
    'ResI_*.nii.gz', ...
    'batch_one_sample_t.mat', ...
    'included_subjects.txt', ...
    'input_manifest.tsv' ...
};

for pattern_index = 1:numel(patterns_to_remove)

    matching_files = dir( ...
        fullfile( ...
            output_directory, ...
            patterns_to_remove{pattern_index} ...
        ) ...
    );

    for file_index = 1:numel(matching_files)

        file_path = fullfile( ...
            output_directory, ...
            matching_files(file_index).name ...
        );

        if exist(file_path, 'file') == 2
            delete(file_path);
        end
    end
end

end


function write_subject_manifest( ...
    output_directory, ...
    subject_names ...
)
% Save participant IDs included in the second-level model.

manifest_path = fullfile( ...
    output_directory, ...
    'included_subjects.txt' ...
);

file_id = fopen( ...
    manifest_path, ...
    'w' ...
);

if file_id == -1
    warning( ...
        'Could not create participant manifest: %s', ...
        manifest_path ...
    );
    return;
end

for subject_index = 1:numel(subject_names)

    fprintf( ...
        file_id, ...
        '%s\n', ...
        subject_names{subject_index} ...
    );
end

fclose(file_id);

end


function write_input_manifest( ...
    output_directory, ...
    subject_names, ...
    source_files ...
)
% Save a TSV manifest of participant IDs and input filenames.

manifest_path = fullfile( ...
    output_directory, ...
    'input_manifest.tsv' ...
);

file_id = fopen( ...
    manifest_path, ...
    'w' ...
);

if file_id == -1
    warning( ...
        'Could not create input manifest: %s', ...
        manifest_path ...
    );
    return;
end

fprintf( ...
    file_id, ...
    'participant_id\tinput_file\n' ...
);

for subject_index = 1:numel(subject_names)

    [~, filename, extension] = fileparts( ...
        source_files{subject_index} ...
    );

    if strcmpi(extension, '.gz')

        [~, base_name] = fileparts( ...
            filename ...
        );

        filename = [
            base_name, ...
            '.nii.gz' ...
        ];

    else
        filename = [
            filename, ...
            extension ...
        ];
    end

    fprintf( ...
        file_id, ...
        '%s\t%s\n', ...
        subject_names{subject_index}, ...
        filename ...
    );
end

fclose(file_id);

end


function name = strip_nifti_suffix(file_path)
% Return the filename without .nii or .nii.gz.

[~, name, extension] = fileparts( ...
    file_path ...
);

if strcmpi(extension, '.gz')

    [~, name] = fileparts( ...
        name ...
    );
end

end